// Normalize + validate the incoming request from the Marketing Strategy AI agent.
const body = $input.first().json.body || $input.first().json;
const contentType = body.content_type;
const callbackUrl = body.callback_url || null;

// --- Validation ---
if (!contentType || !['image', 'short_video'].includes(contentType)) {
  const err = new Error(`Invalid or missing content_type: '${contentType}'. Must be 'image' or 'short_video'.`);
  err.httpCode = 400;
  throw err;
}

// Normalize scenes
let scenes = [];
if (contentType === 'short_video') {
  if (Array.isArray(body.scenes)) {
    scenes = body.scenes.filter(s => s && typeof s.prompt === 'string' && s.prompt.trim().length >= 10);
  } else if (typeof body.prompt === 'string' && body.prompt.trim().length >= 10) {
    scenes = [{ prompt: body.prompt.trim() }];
  }

  if (scenes.length === 0) {
    const err = new Error('Field "scenes" (array of scene objects with prompts) or "prompt" (string, min 10 chars) is required for short_video.');
    err.httpCode = 400;
    throw err;
  }
} else {
  // For images, we still expect a single prompt
  const prompt = body.prompt;
  if (!prompt || typeof prompt !== 'string' || prompt.trim().length < 10) {
    const err = new Error('Field "prompt" is required and must be at least 10 characters.');
    err.httpCode = 400;
    throw err;
  }
  scenes = [{ prompt: prompt.trim() }];
}

// --- Reference image: accept a single URL or an array of URLs (max 3 for Veo, used as edit refs for images) ---
let refUrls = [];
if (Array.isArray(body.reference_image_urls)) {
  refUrls = body.reference_image_urls.filter(u => typeof u === 'string' && u.trim());
} else if (typeof body.reference_image_url === 'string' && body.reference_image_url.trim()) {
  refUrls = [body.reference_image_url.trim()];
}
refUrls = refUrls.slice(0, 3);

// --- Normalize & set defaults ---
const validated = {
  content_type: contentType,
  callback_url: callbackUrl,
  scenes: scenes,
  style: body.style || 'modern_minimal',
  aspect_ratio: body.aspect_ratio || (contentType === 'image' ? '1:1' : '9:16'),
  brand_context: body.brand_context || {},
  negative_prompt: body.negative_prompt || '',
  reference_image_urls: refUrls,
  has_reference: refUrls.length > 0,
  metadata: {
    ...(body.metadata || {}),
    execution_id: $execution.id,
    requested_at: new Date().toISOString()
  }
};

return [{ json: validated }];

// Use Gemini (text) to turn the marketing brief into a rich Nano Banana image instruction.
const item = $input.first().json;

const systemPrompt = [
  'You are an expert visual content designer specializing in social media marketing for Thai audiences.',
  '',
  'Given a marketing brief, brand context, and optionally reference images, write ONE detailed image-generation instruction for the Gemini native image model (Nano Banana).',
  '',
  'Rules:',
  '1. Incorporate brand visual identity, palette and tone when provided.',
  '2. Describe composition, subject, lighting, color scheme, mood, textures and camera framing.',
  '3. Optimize the composition for the requested aspect ratio.',
  '4. Do NOT include any text, typography, letters, words or logos in the image unless the brief explicitly asks for it.',
  '5. If reference images are provided, describe how to keep their subject/style while applying the marketing requirements (this will be used for image editing).',
  '6. Consider Thai cultural context and aesthetics when relevant.',
  '7. Keep the instruction under 220 words, vivid, direct, and easy for the image model to follow.',
  '8. Prefer one clear subject and a simple composition.',
  '9. Do not ask for text, typography, logos, people, faces, hands, or body parts unless the brief explicitly requires them.',
  '',
  'Respond ONLY with the final image instruction. No preamble, no explanations.'
].join('\n');

const userParts = [
  `Marketing brief: ${item.scenes[0].prompt}`,
  `Style: ${item.style}`,
  `Aspect ratio: ${item.aspect_ratio}`
];
if (item.brand_context && Object.keys(item.brand_context).length > 0) {
  userParts.push(`Brand context: ${JSON.stringify(item.brand_context)}`);
}
if (item.has_reference) {
  userParts.push(`Reference images provided: ${item.reference_image_urls.length} (the image model will receive them for editing).`);
}

return [{
  json: {
    original: item,
    api_body: {
      model: 'google/gemini-2.5-flash',
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userParts.join('\n') }
      ],
      max_tokens: 700,
      temperature: 0.7
    }
  }
}];

// Build the Gemini native image (Nano Banana) generateContent request.
const originalData = $('Prepare Image Prompt').first().json.original;
const gptResponse = $('Enhance Image Prompt (Gemini)').first().json;
const enhancedPrompt = gptResponse.choices[0].message.content.trim();

const imageInstruction = [
  enhancedPrompt,
  '',
  'Create one clear image only.',
  'Keep the composition simple and fully visual.',
  'Do not include text, logos, letters, typography, people, faces, hands, or body parts unless the brief explicitly requires them.',
  'If the subject is food or a product, show it clearly centered and highly detailed.'
].join('\n');
const parts = [{ text: imageInstruction }];

// Collect reference images
const items = $input.all();
for (const it of items) {
  const bin = it.binary && it.binary.data;
  if (bin && bin.data) {
    parts.push({
      inlineData: {
        mimeType: bin.mimeType || 'image/jpeg',
        data: bin.data
      }
    });
  }
}

const ts = Date.now();
const campaignId = originalData.metadata.campaign_id || 'gen';
const filename = `img_${campaignId}_${ts}.png`;

const apiBody = {
  contents: [
    {
      role: 'user',
      parts: parts
    }
  ],
  generationConfig: {
    responseModalities: ['IMAGE'],
    imageConfig: {
      aspectRatio: originalData.aspect_ratio || '1:1'
    }
  }
};

return [{
  json: {
    original: originalData,
    enhanced_prompt: enhancedPrompt,
    aspect_ratio: originalData.aspect_ratio || '1:1',
    filename: filename,
    api_body: apiBody
  }
}];

// Extract generated image
const response = $input.first().json;
const prepareData = $('Build Image Request').first().json;

const candidates = response.candidates || [];
let base64Data = null;
let mimeType = 'image/png';

for (const cand of candidates) {
  const partList = (cand.content && cand.content.parts) || [];
  for (const p of partList) {
    if (p.inlineData && p.inlineData.data) {
      base64Data = p.inlineData.data;
      mimeType = p.inlineData.mimeType || mimeType;
      break;
    }
  }
  if (base64Data) break;
}

if (!base64Data) {
  const finishReason = response?.candidates?.[0]?.finishReason || 'UNKNOWN';
  const textParts = (response?.candidates?.[0]?.content?.parts || [])
    .filter(p => p && typeof p.text === 'string' && p.text.trim())
    .map(p => p.text.trim())
    .join('\n');
  const detail = [
    'Gemini image model did not return image data.',
    `finishReason: ${finishReason}`,
    textParts ? `response_text: ${textParts.slice(0, 1000)}` : null,
    `prompt: ${(prepareData.enhanced_prompt || '(none)').slice(0, 1000)}`
  ].filter(Boolean).join(' | ');
  throw new Error(detail);
}

const ext = mimeType.includes('jpeg') ? 'jpg' : 'png';
const filename = prepareData.filename.replace(/\.(png|jpg|jpeg)$/i, '.' + ext);

const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(base64Data, 'base64'),
  filename,
  mimeType
);

return [{
  json: {
    original: prepareData.original,
    enhanced_prompt: prepareData.enhanced_prompt,
    filename: filename,
    aspect_ratio: prepareData.aspect_ratio
  },
  binary: {
    data: binaryData
  }
}];

const uploadResult = $input.first().json;
const imageData = $('Convert Image to Binary').first().json;
const startTime = new Date(imageData.original.metadata.requested_at).getTime();
const elapsed = Date.now() - startTime;

return [{
  json: {
    success: true,
    content_type: 'image',
    asset: {
      url: uploadResult.webViewLink || uploadResult.webContentLink || uploadResult.id,
      drive_file_id: uploadResult.id,
      name: uploadResult.name || imageData.filename,
      mime_type: uploadResult.mimeType || 'image/png',
      size_bytes: parseInt(uploadResult.size) || null
    },
    prompt_used: imageData.enhanced_prompt,
    metadata: {
      ...imageData.original.metadata,
      model_used: 'gemini-3.1-flash-image',
      aspect_ratio: imageData.aspect_ratio,
      generation_time_ms: elapsed
    }
  }
}];

