// Use Gemini (text) to turn the marketing brief into a detailed Veo prompt.
const item = $input.first().json;

const systemPrompt = [
  'You are an expert short-form video content creator specializing in social media marketing.',
  '',
  'Given a marketing brief and brand context, write ONE detailed prompt for the Veo video model.',
  '',
  'Rules:',
  '1. Describe scene composition, subject, action, camera movement and visual flow.',
  '2. Specify mood, lighting and color grading.',
  '3. Optimize for the requested aspect ratio (vertical 9:16 by default for social media).',
  '4. Keep the scene simple, focused and visually striking — one clear subject and motion.',
  '5. Avoid on-screen text, typography or complex multi-character interactions.',
  '6. Avoid showing people, faces, hands, or body parts unless the brief explicitly requires them.',
  '7. For food or product ads, keep the focus on the dish, ingredients, utensils, lighting, texture and motion.',
  '8. Consider Thai cultural context when relevant.',
  '9. If a reference image is provided it defines the subject/first frame; keep that subject consistent.',
  '',
  'Respond ONLY with the final video prompt. No explanations.'
].join('\n');

const userParts = [
  `Marketing brief: ${item.prompt}`,
  `Style: ${item.style}`,
  `Aspect ratio: ${item.aspect_ratio}`
];
if (item.brand_context && Object.keys(item.brand_context).length > 0) {
  userParts.push(`Brand context: ${JSON.stringify(item.brand_context)}`);
}
if (item.has_reference) {
  userParts.push('A reference image will be supplied as the starting frame / subject.');
}
userParts.push('Important: keep the scene food-focused, object-focused, and free from people, faces, hands, and body parts.');

return [{
  json: {
    original: item,
    api_body: {
      model: 'google/gemini-2.5-flash',
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userParts.join('\n') }
      ],
      max_tokens: 600,
      temperature: 0.7
    }
  }
}];

const runIndex = $('Loop Scenes').context.currentRunIndex || 0;
let delaySeconds = 0;
if (runIndex > 0) {
  try {
    const lastExtract = $('Extract Task Info').first(0, runIndex - 1);
    if (lastExtract && lastExtract.json) {
      const lastSubmittedAt = new Date(lastExtract.json.submitted_at).getTime();
      const now = Date.now();
      const elapsedMs = now - lastSubmittedAt;
      const requiredMs = 65 * 1000; // 65 seconds to be safe
      if (elapsedMs < requiredMs) {
        delaySeconds = Math.ceil((requiredMs - elapsedMs) / 1000);
      }
    }
  } catch (e) {
    // fallback
  }
}
return [{ 
  json: {
    ...$input.first().json,
    delay_seconds: delaySeconds,
    should_wait: delaySeconds > 0
  }
}];

// Build the Veo 3.1 predictLongRunning request body (text-to-video or image-to-video).
const originalData = $('Prepare Video Prompt').first().json.original;
const gptResponse = $('Enhance Video Prompt (Gemini)').first().json;
const enhancedPrompt = gptResponse.choices[0].message.content.trim();

let imageBase64 = null;
let mimeType = 'image/jpeg';
try {
  const bin = $input.first().binary && $input.first().binary.data;
  if (bin && bin.data) {
    imageBase64 = bin.data;
    mimeType = bin.mimeType || 'image/jpeg';
  }
} catch (e) {
  // no reference image
}

const aspectRatio = originalData.aspect_ratio === '16:9' ? '16:9' : '9:16';

// Check if this is a video extension based on loop index
const runIndex = $('Loop Scenes').context.currentRunIndex || 0;
const isExtension = runIndex > 0;
let previousVideoGcsUri = null;
if (isExtension) {
  try {
    const allRuns = $('Evaluate Video Status').all();
    if (allRuns && allRuns.length > 0) {
      previousVideoGcsUri = allRuns[allRuns.length - 1].json.gcs_url;
    }
  } catch (e) {
    // fallback
  }
}

const instance = { prompt: enhancedPrompt };
if (isExtension && previousVideoGcsUri) {
  instance.video = {
    gcsUri: previousVideoGcsUri,
    mimeType: 'video/mp4'
  };
} else if (imageBase64) {
  instance.image = {
    bytesBase64Encoded: imageBase64,
    mimeType: mimeType
  };
}

// Vertex AI Veo 3.1 video extension only supports exactly 7 seconds length for extension segments
const duration = isExtension ? 7 : 8;

const parameters = {
  storageUri: 'gs://' + ($env.GCP_VEO_OUTPUT_BUCKET || 'your-bucket-name') + '/veo/',
  sampleCount: 1,
  aspectRatio: aspectRatio,
  resolution: '720p',
  durationSeconds: duration
};
if (originalData.negative_prompt) {
  parameters.negativePrompt = originalData.negative_prompt;
}

return [{
  json: {
    original: originalData,
    enhanced_prompt: enhancedPrompt,
    is_extension: isExtension,
    reference_video_url: previousVideoGcsUri,
    api_body: {
      instances: [instance],
      parameters: parameters
    },
    submitted_at: new Date().toISOString()
  }
}];

const submitResponse = $input.first().json;
const jobData = $('Build Video Job').item.json;

const taskId = submitResponse.name;
if (!taskId) {
  throw new Error('Failed to get operation name from Veo API. Response: ' + JSON.stringify(submitResponse).slice(0, 1000));
}

const original = jobData?.original || {};
const campaignId = original.metadata?.campaign_id || 'gen';

return [{
  json: {
    task_id: taskId,
    original: original,
    enhanced_prompt: jobData?.enhanced_prompt || '',
    submitted_at: jobData?.submitted_at || new Date().toISOString(),
    filename: `vid_${campaignId}_${Date.now()}.mp4`
  }
}];

// Evaluate the Veo operation status and normalize it for routing.
const statusResponse = $input.first().json;
const taskInfo = $('Extract Task Info').item.json;

const elapsed = Date.now() - new Date(taskInfo.submitted_at).getTime();
const maxDuration = 10 * 60 * 1000;

if (elapsed > maxDuration) {
  return [{
    json: {
      status: 'failed',
      error_message: `Video generation timed out after ${Math.round(elapsed / 1000)}s`,
      task_id: taskInfo.task_id,
      original: taskInfo.original,
      elapsed_ms: elapsed
    }
  }];
}

const isDone = statusResponse.done === true;
let videoUrl = null;
let errorMsg = null;

// Support both official Vertex AI schema (response.videos[0].gcsUri) and AI Studio schema
const rawUri = isDone ? (statusResponse.response?.videos?.[0]?.gcsUri || statusResponse.response?.generateVideoResponse?.generatedSamples?.[0]?.video?.uri) : null;

if (isDone) {
  const apiError = statusResponse.error || statusResponse.response?.error;
  if (apiError) {
    errorMsg = apiError.message || JSON.stringify(apiError);
  } else if (!rawUri) {
    errorMsg = 'Could not find video URI in finished response: ' + JSON.stringify(statusResponse).slice(0, 1000);
  } else {
    try {
      const match = rawUri.match(/^gs:\/\/([^\/]+)\/(.+)$/);
      if (match) {
        const bucket = match[1];
        const object = encodeURIComponent(match[2]);
        videoUrl = `https://storage.googleapis.com/download/storage/v1/b/${bucket}/o/${object}?alt=media`;
      } else {
        videoUrl = rawUri;
      }
    } catch (e) {
      errorMsg = 'Error parsing GCS URI: ' + e.message;
    }
  }
}

let normalizedStatus = 'processing';
if (isDone) {
  normalizedStatus = errorMsg ? 'failed' : 'completed';
}

return [{
  json: {
    status: normalizedStatus,
    video_url: videoUrl,
    gcs_url: rawUri,
    task_id: taskInfo.task_id,
    original: taskInfo.original,
    enhanced_prompt: taskInfo.enhanced_prompt,
    filename: taskInfo.filename,
    submitted_at: taskInfo.submitted_at,
    elapsed_ms: elapsed,
    error_message: errorMsg
  }
}];

const data = $input.first().json;

return [{
  json: {
    success: false,
    content_type: 'short_video',
    error: {
      code: 'VIDEO_GENERATION_FAILED',
      message: data.error_message || 'Video generation failed.',
      task_id: data.task_id,
      elapsed_ms: data.elapsed_ms,
      scene_prompt: data.original?.prompt || data.original?.scene_prompt || null,
      scene_index: data.original?.scene_index || null
    },
    metadata: {
      ...(data.original?.metadata || {}),
      task_id: data.task_id,
      scene_prompt: data.original?.prompt || data.original?.scene_prompt || null,
      scene_index: data.original?.scene_index || null
    }
  }
}];

const item = $input.first().json;

return [{
  json: {
    success: false,
    content_type: item.content_type || 'unknown',
    error: {
      code: 'VALIDATION_ERROR',
      message: `Unsupported content_type: '${item.content_type}'. Use 'image' or 'short_video'.`
    },
    metadata: {
      execution_id: $execution.id
    }
  }
}];

const scenesMetadata = $('Evaluate Video Status').all().map((item, index) => {
  const data = item.json;
  return {
    scene_index: index,
    prompt_used: data.enhanced_prompt,
    gcs_url: data.gcs_url,
    elapsed_ms: data.elapsed_ms,
    task_id: data.task_id
  };
});
const uploadResult = $('Upload Video').first().json;
const originalInput = $('Validate Input').first().json;

const finalAsset = {
  url: uploadResult.webViewLink || uploadResult.webContentLink || uploadResult.id,
  drive_file_id: uploadResult.id,
  name: uploadResult.name || scenesMetadata[scenesMetadata.length - 1].name,
  mime_type: uploadResult.mimeType || 'video/mp4',
  size_bytes: parseInt(uploadResult.size) || null,
  gcs_url: scenesMetadata[scenesMetadata.length - 1].gcs_url
};

return [{
  json: {
    callback_url: originalInput.callback_url,
    payload: {
      success: true,
      execution_id: originalInput.metadata.execution_id,
      content_type: 'short_video',
      total_scenes: scenesMetadata.length,
      final_asset: finalAsset,
      scenes_metadata: scenesMetadata
    }
  }
}];
